export function pickTopologies(rng: () => number, count: number): TopologyDef[] {
  const result: TopologyDef[] = [];
  for (let i = 0; i < count; i++) {
    const idx = Math.floor(rng() * TOPOLOGIES.length);
    result.push(TOPOLOGIES[idx]);
  }
  return result;
}

